const items = [];

for (const item of $input.all()) {
  // Split observer fields by comma (from GROUP_CONCAT)
  const emails = (item.json.observer_emails || '').split(',');
  const firstNames = (item.json.observer_first_names || '').split(',');
  const lastNames = (item.json.observer_last_names || '').split(',');

  for (let i = 0; i < emails.length; i++) {
    if (!emails[i]) continue;

    items.push({
      json: {
        ...item.json, // keep all subtask details

        observer_email: emails[i].trim(),
        observer_first_name: firstNames[i]?.trim(),
        observer_last_name: lastNames[i]?.trim()
      }
    });
  }
}

return items;
